































































@use '../../assets/stylesheets/mixins.scss';

.my-courses-color-picker {
    list-style: none;
    margin: 0;
    padding: 0;

    // Hide text in color groups
    li {
        text-indent: 100%;
        overflow: hidden;
        white-space: nowrap;

        position: relative;
    }

    a {
        position: absolute;
        top: 0;
        right: 0;
        bottom: 0;
        left: 0;

        cursor: pointer;
    }

    .color-selected {
        @include mixins.background-icon(accept, info, 32px);
        background-position: center;
        background-repeat: no-repeat;
    }
}
